import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { AuthService } from './auth.service';
import { NotificationService } from '../services/notification.service';
import { ThemeService } from '../services/theme.service';

declare global {
  interface Window {
    google: any;
  }
}

@Component({
  selector: 'app-google-login',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    <div [class]="isDarkMode ? 'dark' : ''" class="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-600 via-blue-500 to-purple-600 dark:from-gray-900 dark:via-gray-800 dark:to-gray-900 relative overflow-hidden transition-colors duration-300">
      <!-- Dark mode toggle button -->
      <button
        (click)="toggleDarkMode()"
        class="fixed top-6 right-6 z-20 p-2 rounded-lg bg-white dark:bg-gray-800 shadow-lg hover:shadow-xl transition-all duration-200"
        [title]="isDarkMode ? 'Switch to Light Mode' : 'Switch to Dark Mode'">
        <svg *ngIf="!isDarkMode" class="w-6 h-6 text-gray-900" fill="currentColor" viewBox="0 0 20 20">
          <!-- Moon icon -->
          <path d="M17.293 13.293A8 8 0 016.707 2.707a8.001 8.001 0 1010.586 10.586z"></path>
        </svg>
        <svg *ngIf="isDarkMode" class="w-6 h-6 text-yellow-400" fill="currentColor" viewBox="0 0 20 20">
          <!-- Sun icon -->
          <path fill-rule="evenodd" d="M10 2a1 1 0 011 1v2a1 1 0 11-2 0V3a1 1 0 011-1zm4 8a4 4 0 11-8 0 4 4 0 018 0zm-.464 4.95l-2.12-2.12a4 4 0 005.656 5.656l2.12-2.12A6 6 0 1013.536 12.95zM16 12a1 1 0 112 0 1 1 0 01-2 0zm2-8a1 1 0 100-2 1 1 0 000 2zM2 12a1 1 0 100-2 1 1 0 000 2zm10-10a1 1 0 100-2 1 1 0 000 2z" clip-rule="evenodd"></path>
        </svg>
      </button>

      <!-- Animated background blobs -->
      <div class="absolute top-0 -left-40 w-80 h-80 bg-blue-400 dark:bg-blue-900 rounded-full mix-blend-multiply filter blur-3xl opacity-20 dark:opacity-10 animate-blob"></div>
      <div class="absolute top-0 -right-40 w-80 h-80 bg-purple-400 dark:bg-purple-900 rounded-full mix-blend-multiply filter blur-3xl opacity-20 dark:opacity-10 animate-blob animation-delay-2000"></div>
      <div class="absolute -bottom-8 left-20 w-80 h-80 bg-pink-400 dark:bg-pink-900 rounded-full mix-blend-multiply filter blur-3xl opacity-20 dark:opacity-10 animate-blob animation-delay-4000"></div>

      <!-- Main card -->
      <div class="relative z-10 w-full max-w-md px-4">
        <div class="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl dark:shadow-gray-900/50 p-8 md:p-12 backdrop-blur-lg bg-opacity-95 dark:bg-opacity-95 transition-colors duration-300">
          <!-- Header -->
          <div class="text-center mb-8">
            <div class="inline-block bg-gradient-to-r from-blue-600 to-purple-600 dark:from-blue-500 dark:to-purple-500 rounded-lg p-3 mb-4 shadow-lg">
              <svg class="w-8 h-8 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path d="M10.5 1.5H3.75A2.25 2.25 0 001.5 3.75v12.5A2.25 2.25 0 003.75 18.5h12.5a2.25 2.25 0 002.25-2.25V9.5M10.5 1.5v8m0 0l-3-3m3 3l3-3M18.5 1.5v6m0 0h-6m6 0l-2-2m2 2l2-2"/>
              </svg>
            </div>
            <h1 class="text-4xl font-bold text-gray-900 dark:text-white mb-2">ACBS</h1>
            <p class="text-gray-600 dark:text-gray-300 text-sm font-medium">Academic Consultation Booking System</p>
          </div>

          <!-- Features list -->
          <div class="mb-8 space-y-3">
            <div class="flex items-center text-sm text-gray-700 dark:text-gray-300">
              <div class="w-5 h-5 bg-green-500 dark:bg-green-600 rounded-full flex items-center justify-center mr-3 flex-shrink-0">
                <svg class="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clip-rule="evenodd" />
                </svg>
              </div>
              <span>Book consultations with teachers</span>
            </div>
            <div class="flex items-center text-sm text-gray-700 dark:text-gray-300">
              <div class="w-5 h-5 bg-green-500 dark:bg-green-600 rounded-full flex items-center justify-center mr-3 flex-shrink-0">
                <svg class="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clip-rule="evenodd" />
                </svg>
              </div>
              <span>Manage your schedule</span>
            </div>
            <div class="flex items-center text-sm text-gray-700 dark:text-gray-300">
              <div class="w-5 h-5 bg-green-500 dark:bg-green-600 rounded-full flex items-center justify-center mr-3 flex-shrink-0">
                <svg class="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clip-rule="evenodd" />
                </svg>
              </div>
              <span>Real-time notifications</span>
            </div>
          </div>

          <!-- Divider -->
          <div class="relative mb-8">
            <div class="absolute inset-0 flex items-center">
              <div class="w-full border-t border-gray-300 dark:border-gray-600"></div>
            </div>
            <div class="relative flex justify-center text-sm">
